def temperaturecolor(k:numbers.Real):
    if k < 6688.07537:
        r = 255
    else:
        r = 329.698737446*(k/100-60)**-0.1332047592
    if k < 500:
        g = 0
    elif k < 6519.59524:
        g = max(99.4708025861*math.log(k/100)-161.1195681661,0)
    else:
        g = 288.1221695283*(k/100-60)**-0.0755148492
    if k < 6904.49542622:
        b = 0
    elif k < 11700.4272:
        b = 138.5177615561*math.log(k/100-60)-305.0447927307
    else:
        b = 255
    return (r,g,b)
def di(n):
    if n < 0:
        return -1
    if n == 0:
        return 0
    if n > 0:
        return 1
def logistic(n):
    if n <= -700:
        return 0
    if n >= 700:
        return 1
    else:
        return 1/(1+math.exp(-1*n))
